import { describe, it, expect } from 'vitest';
import { deployInfrastructure, processInfrastructureTelemetry, isInfrastructureEvaporated } from '../void-infrastructure';
import { createObserver } from '../void-game-engine';

describe('void-infrastructure', () => {
  it('deploys an MCP server as a physical observer and tracks evaporation', () => {
    const owner = createObserver('user:1', 2, 'scientist', 'builder', 'fermion');
    
    // Deploy MCP
    let mcpNode = deployInfrastructure(owner, 'mcp_server', 'topology-mcp', { dimension: 2, x: 10, y: -10, z: 0, t: 0 });
    
    expect(mcpNode.classType).toBe('mcp_server');
    expect(mcpNode.anchor.particleType).toBe('fermion');
    expect(mcpNode.anchor.majorPhyle).toBe('scientist');
    
    // Process heavy telemetry (drain energy)
    mcpNode = processInfrastructureTelemetry(mcpNode, {
      httpRequests: 0,
      mcpToolCalls: 1000, // Massive drain
      backgroundCycles: 100
    });
    
    expect(isInfrastructureEvaporated(mcpNode)).toBe(true);
    expect(mcpNode.anchor.energy).toBe(0);
    expect(mcpNode.anchor.wisdom).toBeGreaterThan(0); // Wisdom gained globally while dying
  });

  it('generates energy via edge web HTTP traffic', () => {
    const owner = createObserver('user:2', 1, 'mystic', 'aesthete', 'boson');
    let siteNode = deployInfrastructure(owner, 'static_site', 'forkjoin-app', { dimension: 1, x: 0, y: 0, z: 0, t: 0 });
    
    const initialEnergy = siteNode.anchor.energy;

    // Receive HTTP traffic (generates HEX)
    siteNode = processInfrastructureTelemetry(siteNode, {
      httpRequests: 500,
      mcpToolCalls: 0,
      backgroundCycles: 10
    });

    expect(siteNode.anchor.energy).toBeGreaterThan(initialEnergy);
    expect(isInfrastructureEvaporated(siteNode)).toBe(false);
  });
});
